// Always initialize dataLayer first (safe to call multiple times)
window.dataLayer = window.dataLayer || [];


/* =============================================================================
   EVENT 1: FORM SUBMISSION
   Fires when any form is submitted on purebrain.ai.
   GTM has a native Form Submission trigger so this JS snippet is OPTIONAL
   for basic form tracking. Use it only if you need to pass form_name.

   WHERE TO ADD:
   Add to each form's submit handler, OR use the GTM Form Submission trigger
   (which fires automatically without this snippet).

   FORM NAME VALUES to use:
   - 'assessment_form'   for the AI Adoption Assessment
   - 'contact_form'      for any contact/inquiry form
   - 'waitlist_form'     for invite/waitlist signups
   - 'demo_request_form' for demo request forms
============================================================================= */

// Option A: Inline on each form's onsubmit
function trackFormSubmission(formName) {
  window.dataLayer = window.dataLayer || [];
  dataLayer.push({
    event: 'form_submission',
    form_name: formName,
    page_location: window.location.href
  });
}

