/* =============================================================================
   EVENT 2: CHATBOX INTERACTION
   Fires when a user interacts with the PureBrain chatbox.

   WHERE TO ADD:
   In the chatbox JavaScript — wherever message send or chatbox open is handled.
   Look in: pay-test-script-chat-flow.js or the chatbox init code.

   INTERACTION_TYPE VALUES:
   - 'chatbox_opened'    when user clicks to open the chatbox
   - 'message_sent'      when user sends their first message
   - 'conversation_started' when the first AI response is received
============================================================================= */

// Fire when chatbox is opened
function trackChatboxOpen() {
  window.dataLayer = window.dataLayer || [];
  dataLayer.push({
    event: 'chatbox_interaction',
    interaction_type: 'chatbox_opened',
    page_location: window.location.href
  });
}

// Fire when user sends first message
function trackChatboxMessage() {
  window.dataLayer = window.dataLayer || [];
  dataLayer.push({
    event: 'chatbox_interaction',
    interaction_type: 'message_sent',
    page_location: window.location.href
  });
}

// Fire when conversation officially starts (first AI response received)
function trackConversationStarted() {
  window.dataLayer = window.dataLayer || [];
  dataLayer.push({
    event: 'chatbox_interaction',
    interaction_type: 'conversation_started',
    page_location: window.location.href
  });
}

