/* =============================================================================
   EVENT 3: PURCHASE (PayPal Payment Completion)
   Fires when a PayPal payment completes successfully.
   This is an e-commerce event — GA4 will track it as revenue.

   WHERE TO ADD:
   In the PayPal success callback — look in pay-test-script-paypal.js
   or wherever onApprove() is handled after payment capture.

   TIER VALUES (update to match actual PureBrain pricing):
   - 'starter'   for $X/month tier
   - 'pro'       for $X/month tier
   - 'enterprise' for enterprise plan

   CURRENCY: Always 'USD'
============================================================================= */

/**
 * Track a completed PayPal purchase
 * @param {string} transactionId - PayPal order ID or transaction ID
 * @param {number} value - Dollar amount paid (e.g., 49.00)
 * @param {string} tierName - Plan name (e.g., 'starter', 'pro', 'enterprise')
 */
function trackPurchase(transactionId, value, tierName) {
  window.dataLayer = window.dataLayer || [];
  dataLayer.push({
    event: 'purchase',
    transaction_id: transactionId,
    value: value,
    currency: 'USD',
    items: [
      {
        item_id: tierName,
        item_name: 'PureBrain ' + tierName.charAt(0).toUpperCase() + tierName.slice(1),
        item_category: 'AI Partnership Plan',
        price: value,
        quantity: 1
      }
    ]
  });
}

/*
  INTEGRATION EXAMPLE — in your PayPal onApprove callback:

  paypal.Buttons({
    createOrder: function(data, actions) {
      // ... existing create order logic
    },
    onApprove: function(data, actions) {
      return actions.order.capture().then(function(details) {

        // Fire the GA4 purchase event
        var transactionId = details.id;
        var amount = parseFloat(details.purchase_units[0].amount.value);
        var tierName = 'pro'; // Replace with actual tier from your UI state

        trackPurchase(transactionId, amount, tierName);

        // ... existing post-payment logic (redirect, show thank you, etc.)
      });
    }
  }).render('#paypal-button-container');
*/


/* =============================================================================
   EVENT 4: ASSESSMENT START
   Fires when a user begins the AI Adoption Assessment.

   TWO OPTIONS — pick whichever fits your setup:

   OPTION A: No JS needed — use the GTM URL-based trigger
   The GTM trigger is already configured to fire on page views where
   the URL contains "assessment". If your assessment lives at a URL like
   purebrain.ai/assessment or purebrain.ai/?page_id=XXX and that page
   has "assessment" in the URL, no JS snippet is required.

   OPTION B: dataLayer push — use if URL doesn't contain "assessment"
   or if you want to track first question click instead of page load.
============================================================================= */

// OPTION B — Add to assessment page initialization:
function trackAssessmentStart(assessmentType) {
  window.dataLayer = window.dataLayer || [];
  dataLayer.push({
    event: 'assessment_start',
    assessment_type: assessmentType || 'ai_adoption_assessment',
    page_location: window.location.href
  });
}

/*
  INTEGRATION EXAMPLE:

  // On assessment page load:
  document.addEventListener('DOMContentLoaded', function() {
    if (document.querySelector('#assessment-container')) {
      trackAssessmentStart('ai_adoption_assessment');
    }
  });

  // OR on first question click:
  var firstQuestion = document.querySelector('.assessment-question:first-child');
  if (firstQuestion) {
    firstQuestion.addEventListener('click', function() {
      trackAssessmentStart('ai_adoption_assessment');
    }, { once: true }); // 'once: true' ensures it only fires once
  }
*/


/* =============================================================================
   EVENT 5: NEWSLETTER SIGNUP (Neural Feed)
   Fires when a user subscribes to the Neural Feed newsletter.

   WHERE TO ADD:
   In the Brevo form submit callback, OR as a WordPress hook after
   the Brevo subscription API call succeeds.

   IF USING BREVO EMBED FORM:
   Brevo embedded forms fire a window event on success.
   Listen for that event and push to dataLayer.

   SIGNUP_SOURCE VALUES:
   - 'blog_inline'        for inline form in blog posts
   - 'blog_sidebar'       for sidebar subscribe widget
   - 'homepage'           for homepage signup
   - 'popup'              for popup/modal signup
   - 'footer'             for footer signup form
   - 'assessment_thank_you' for post-assessment signup
============================================================================= */

/**
 * Track a newsletter signup
 * @param {string} signupSource - Where the signup happened
 */
function trackNewsletterSignup(signupSource) {
  window.dataLayer = window.dataLayer || [];
  dataLayer.push({
    event: 'newsletter_signup',
    signup_source: signupSource || 'unknown',
    page_location: window.location.href
  });
}

