/* =============================================================================
   UTILITY: Debug helper
   Enable during development to confirm events are firing.
   REMOVE before going live.
============================================================================= */

// Optional: Log all dataLayer pushes during testing
// Remove this block before production deployment
(function() {
  if (window.location.hostname === 'localhost' || window.location.search.indexOf('gtm_debug') > -1) {
    var originalPush = Array.prototype.push;
    window.dataLayer = window.dataLayer || [];

    // Override push to log events
    window.dataLayer.push = function() {
      console.log('[GTM DataLayer Event]', arguments[0]);
      return originalPush.apply(this, arguments);
    };
  }
})();


/* =============================================================================
   BREVO-SPECIFIC: If using Brevo JavaScript forms
   Brevo's embed code creates a global object. This checks for success.
============================================================================= */

// Brevo success detection (works with Brevo embedded form v3+)
document.addEventListener('DOMContentLoaded', function() {
  // Find all Brevo forms on page
  var brevoForms = document.querySelectorAll('[data-form-id]');
  brevoForms.forEach(function(form) {
    // Determine source from form location in DOM
    var signupSource = 'unknown';
    if (form.closest('.blog-post') || form.closest('article')) {
      signupSource = 'blog_inline';
    } else if (form.closest('.sidebar') || form.closest('#sidebar')) {
      signupSource = 'blog_sidebar';
    } else if (form.closest('footer') || form.closest('#footer')) {
      signupSource = 'footer';
    } else if (document.body.classList.contains('home')) {
      signupSource = 'homepage';
    }

    // Listen for Brevo's success event on this form
    form.addEventListener('submit', function() {
      // Small delay to let Brevo validate before we track
      setTimeout(function() {
        if (form.classList.contains('sib-form--success') || document.querySelector('.sib-form-message-panel--active')) {
          trackNewsletterSignup(signupSource);
        }
      }, 1000);
    });
  });
});
